"""Auto-generated style UI setup for the main window.

NOTE: In production this would be generated from mainwindow.ui via pyside6-uic.
For initial development, we create the UI programmatically following the
design spec wireframe (section 3.1).

DO NOT EDIT this file manually in production — use Qt Designer.
"""

from __future__ import annotations

from PySide6.QtCore import Qt
from PySide6.QtWidgets import (
    QCheckBox,
    QComboBox,
    QGroupBox,
    QHBoxLayout,
    QHeaderView,
    QLabel,
    QMainWindow,
    QPlainTextEdit,
    QPushButton,
    QScrollArea,
    QSizePolicy,
    QTableWidget,
    QVBoxLayout,
    QWidget,
)

from app.ui.widgets.flow_layout import FlowLayout

# Maximum content width — beyond this, side margins absorb extra space
_MAX_CONTENT_WIDTH = 2800

_GLOBAL_STYLESHEET = """
* {
    font-family: "Yu Gothic UI", "Meiryo UI", "Segoe UI", sans-serif;
}

QMainWindow {
    background: #f5f7fa;
}

QLabel {
    color: #333;
    font-size: 13px;
}

QGroupBox QLabel {
    background: #ffffff;
}

QGroupBox {
    font-size: 13px;
    font-weight: bold;
    color: #444;
    border: 1px solid #e0e0e0;
    border-radius: 6px;
    margin-top: 14px;
    padding: 16px 12px 10px 12px;
    background: #ffffff;
}
QGroupBox::title {
    subcontrol-origin: margin;
    subcontrol-position: top left;
    padding: 2px 8px;
    color: #555;
}

QComboBox {
    border: 1px solid #d0d0d0;
    border-radius: 4px;
    padding: 5px 10px;
    background: #ffffff;
    color: #333;
    font-size: 13px;
    min-height: 22px;
}
QComboBox:hover { border-color: #999; }
QComboBox::drop-down {
    subcontrol-origin: padding;
    subcontrol-position: center right;
    width: 20px;
    border: none;
}
QComboBox QAbstractItemView {
    background: #ffffff;
    color: #333;
    selection-background-color: #e3f2fd;
    selection-color: #1565c0;
    border: 1px solid #d0d0d0;
    padding: 4px;
}

QTableWidget {
    border: 1px solid #e0e0e0;
    border-radius: 4px;
    gridline-color: #eee;
    font-size: 12px;
    background: #ffffff;
    alternate-background-color: #fafbfc;
    color: #333;
}
QHeaderView::section {
    background: #f5f7fa;
    border: none;
    border-bottom: 2px solid #ddd;
    padding: 5px 8px;
    font-size: 12px;
    font-weight: bold;
    color: #555;
}

QPlainTextEdit {
    border: 1px solid #d0d0d0;
    border-radius: 4px;
    padding: 6px;
    background: #ffffff;
    color: #333;
    font-size: 13px;
}
QPlainTextEdit:focus { border-color: #90caf9; }

QScrollArea {
    border: 1px solid #e0e0e0;
    border-radius: 4px;
    background: #ffffff;
}

QCheckBox {
    spacing: 6px;
    font-size: 13px;
    color: #444;
    background: transparent;
}

QLabel#lbl_status {
    font-size: 12px;
    color: #888;
    padding: 2px 0;
}
"""


class Ui_MainWindow:
    """Sets up the main window UI matching design spec 3.1."""

    def setupUi(self, main_window: QMainWindow) -> None:
        main_window.setObjectName("MainWindow")
        main_window.setWindowTitle("水質報告ツール")
        main_window.resize(900, 750)
        main_window.setMinimumSize(700, 550)
        main_window.setStyleSheet(_GLOBAL_STYLESHEET)

        # Central widget — outer wrapper centres a max-width container
        central = QWidget()
        main_window.setCentralWidget(central)
        outer_layout = QHBoxLayout(central)
        outer_layout.setContentsMargins(0, 0, 0, 0)
        outer_layout.setSpacing(0)

        # Max-width content container
        content = QWidget()
        content.setMaximumWidth(_MAX_CONTENT_WIDTH)
        content.setStyleSheet("background: transparent;")
        outer_layout.addStretch()
        outer_layout.addWidget(content)
        outer_layout.addStretch()

        root_layout = QVBoxLayout(content)
        root_layout.setContentsMargins(24, 20, 24, 20)
        root_layout.setSpacing(14)

        # --- Header ---
        header_layout = QHBoxLayout()
        self.lbl_title = QLabel("水質報告ツール")
        self.lbl_title.setStyleSheet(
            "font-size: 20px; font-weight: bold; color: #333; background: transparent;"
        )
        header_layout.addWidget(self.lbl_title)
        header_layout.addStretch()
        self.btn_settings = QPushButton("設定")
        self.btn_settings.setFixedWidth(80)
        self.btn_settings.setStyleSheet(
            "QPushButton { border: 1px solid #d0d0d0; border-radius: 4px;"
            "  padding: 6px 16px; background: #fff; font-size: 13px; color: #444; }"
            "QPushButton:hover { background: #f0f0f0; border-color: #bbb; }"
        )
        header_layout.addWidget(self.btn_settings)
        root_layout.addLayout(header_layout)

        # --- Zone 1: Report Selection ---
        grp_report = QGroupBox("① 報告書選択")
        grp_report_layout = QVBoxLayout(grp_report)

        row1 = QHBoxLayout()
        row1.addWidget(QLabel("報告書:"))
        self.cmb_report = QComboBox()
        self.cmb_report.setSizePolicy(QSizePolicy.Policy.Expanding, QSizePolicy.Policy.Fixed)
        row1.addWidget(self.cmb_report)
        grp_report_layout.addLayout(row1)

        grp_report_layout.addWidget(QLabel("JOB番号（複数選択可）:"))
        self.job_scroll = QScrollArea()
        self.job_scroll.setWidgetResizable(True)
        self.job_scroll.setMaximumHeight(120)
        self.job_widget = QWidget()
        self.job_widget.setStyleSheet("background: transparent;")
        self.job_flow_layout = FlowLayout(self.job_widget, h_spacing=6, v_spacing=6)
        self.job_flow_layout.setContentsMargins(10, 10, 10, 10)
        self.job_scroll.setWidget(self.job_widget)
        grp_report_layout.addWidget(self.job_scroll)

        # Placeholder for dynamically created JOB tag buttons
        self.job_tags: list[QPushButton] = []

        root_layout.addWidget(grp_report)

        # --- Zone 2: Data Preview ---
        grp_preview = QGroupBox("② データプレビュー")
        grp_preview_layout = QVBoxLayout(grp_preview)

        self.lbl_sample_count = QLabel("対象サンプル: -")
        grp_preview_layout.addWidget(self.lbl_sample_count)

        self.tbl_preview = QTableWidget()
        self.tbl_preview.setMinimumHeight(150)
        self.tbl_preview.setEditTriggers(QTableWidget.EditTrigger.NoEditTriggers)
        self.tbl_preview.setSelectionBehavior(QTableWidget.SelectionBehavior.SelectRows)
        self.tbl_preview.setAlternatingRowColors(True)
        self.tbl_preview.horizontalHeader().setStretchLastSection(True)
        self.tbl_preview.horizontalHeader().setSectionResizeMode(
            QHeaderView.ResizeMode.ResizeToContents
        )
        grp_preview_layout.addWidget(self.tbl_preview)

        root_layout.addWidget(grp_preview)

        # --- Zone 3: Department Distribution ---
        grp_dept = QGroupBox("③ 部署別配信プレビュー")
        grp_dept_layout = QVBoxLayout(grp_dept)

        self.dept_scroll = QScrollArea()
        self.dept_scroll.setWidgetResizable(True)
        self.dept_scroll.setMaximumHeight(180)
        self.dept_widget = QWidget()
        self.dept_list_layout = QVBoxLayout(self.dept_widget)
        self.dept_list_layout.setAlignment(Qt.AlignmentFlag.AlignTop)
        self.dept_scroll.setWidget(self.dept_widget)
        grp_dept_layout.addWidget(self.dept_scroll)

        # Placeholder for dynamically created checkboxes
        self.dept_checkboxes: list[QCheckBox] = []

        root_layout.addWidget(grp_dept)

        # --- Zone 4: Message ---
        grp_msg = QGroupBox("④ 送信メッセージ")
        grp_msg_layout = QVBoxLayout(grp_msg)
        self.txt_message = QPlainTextEdit()
        self.txt_message.setMaximumHeight(80)
        self.txt_message.setPlaceholderText("報告書に添えるメッセージを入力してください...")
        grp_msg_layout.addWidget(self.txt_message)
        root_layout.addWidget(grp_msg)

        # --- Bottom Buttons ---
        btn_layout = QHBoxLayout()
        btn_layout.addStretch()
        self.btn_export = QPushButton("CSV出力・プレビュー")
        self.btn_export.setObjectName("btn_export")
        self.btn_export.setFixedWidth(180)
        self.btn_export.setStyleSheet(
            "QPushButton { background: #1976d2; color: #fff; border: none;"
            "  font-weight: bold; border-radius: 4px; padding: 8px 16px; font-size: 13px; }"
            "QPushButton:hover { background: #1565c0; }"
            "QPushButton:pressed { background: #0d47a1; }"
        )
        btn_layout.addWidget(self.btn_export)

        self.btn_send = QPushButton("送信")
        self.btn_send.setObjectName("btn_send")
        self.btn_send.setFixedWidth(120)
        self.btn_send.setStyleSheet(
            "QPushButton { background: #43a047; color: #fff; border: none;"
            "  font-weight: bold; border-radius: 4px; padding: 8px 16px; font-size: 13px; }"
            "QPushButton:hover { background: #388e3c; }"
            "QPushButton:pressed { background: #2e7d32; }"
        )
        btn_layout.addWidget(self.btn_send)
        root_layout.addLayout(btn_layout)

        # --- Status Bar ---
        self.lbl_status = QLabel("")
        self.lbl_status.setObjectName("lbl_status")
        root_layout.addWidget(self.lbl_status)
